INSERT INTO activities (title, description, activity_date, location) VALUES
('งานสัมมนาใหญ่ประจำปี 2026', 'สัมมนาและฝึกอบรมผู้แทนจำหน่ายทั่วประเทศกว่า 2,000 คน พร้อมพิธีมอบรางวัล Hall of Fame ประจำปี', '2026-06-15', 'ศูนย์การประชุมแห่งชาติสิริกิติ์ กรุงเทพฯ'),
('กิจกรรม CSR ปลูกป่าชายเลน', 'ปลูกต้นไม้กว่า 5,000 ต้น เพื่อฟื้นฟูระบบนิเวศชายฝั่ง ร่วมกับพนักงานและผู้แทนจำหน่ายกว่า 300 คน', '2026-05-20', 'อ่าวไทย จังหวัดสมุทรสาคร'),
('อบรมผู้แทนจำหน่ายใหม่ รุ่น 25', 'อบรมความรู้เชิงลึกเกี่ยวกับผลิตภัณฑ์ ทักษะการขาย และการสร้างทีมงาน สำหรับผู้แทนจำหน่ายใหม่', '2026-07-10', 'สำนักงานใหญ่ บัวหลวง เฮลธ์ กรุงเทพฯ'),
('เทศกาลสุขภาพ Sky Online Health Fair', 'งานมหกรรมสุขภาพ ออกบูธให้คำปรึกษาด้านสุขภาพ สาธิตผลิตภัณฑ์ และกิจกรรมเพื่อสุขภาพมากมาย', '2026-08-05', 'สยามพารากอน กรุงเทพฯ'),
('ทริปท่องเที่ยวรางวัลผู้บริหาร Top 100', 'ทริปพิเศษสำหรับผู้แทนจำหน่ายที่มียอดขายสูงสุด 100 อันดับแรก ประจำครึ่งปีแรก 2026', '2026-09-15', 'เกาะบาหลี ประเทศอินโดนีเซีย');
